// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.SingletonSet;
import org.junit.jupiter.api.Test;

class ProvidedPhysicalPropertiesTest {

	@Test
	void providedLongerOrderingSatisfiesRequiredPrefix() {
		BindingUniverse universe = BindingUniverse.create();
		SortKey first = SortKey.ascending(universe.symbol("first"));
		SortKey second = SortKey.descending(universe.symbol("second"));
		ProvidedPhysicalProperties provided = ProvidedPhysicalProperties.builder()
				.ordering(List.of(first, second))
				.build();
		RequiredPhysicalProperties required = RequiredPhysicalProperties.builder()
				.ordering(List.of(first))
				.build();

		assertTrue(provided.satisfies(required));
	}

	@Test
	void requiredLongerOrderingRejectsShorterProvidedPrefix() {
		BindingUniverse universe = BindingUniverse.create();
		SortKey first = SortKey.ascending(universe.symbol("first"));
		SortKey second = SortKey.descending(universe.symbol("second"));
		ProvidedPhysicalProperties provided = ProvidedPhysicalProperties.builder()
				.ordering(List.of(first))
				.build();
		RequiredPhysicalProperties required = RequiredPhysicalProperties.builder()
				.ordering(List.of(first, second))
				.build();

		assertFalse(provided.satisfies(required));
	}

	@Test
	void providedBindingMasksMustContainRequiredMasks() {
		BindingUniverse universe = BindingUniverse.create();
		ProvidedPhysicalProperties provided = ProvidedPhysicalProperties.builder()
				.distinctBindings(universe.maskOf(List.of("a", "b")))
				.parameterBindings(universe.maskOf(List.of("outerA")))
				.build();

		assertTrue(provided.satisfies(RequiredPhysicalProperties.builder()
				.distinctBindings(universe.maskOf(List.of("a")))
				.parameterBindings(universe.maskOf(List.of("outerA", "outerB")))
				.build()));
		assertFalse(provided.satisfies(RequiredPhysicalProperties.builder()
				.distinctBindings(universe.maskOf(List.of("a", "missing")))
				.parameterBindings(universe.maskOf(List.of("outerA", "outerB")))
				.build()));
	}

	@Test
	void parameterizedPlanDoesNotSatisfyUnboundGoal() {
		BindingUniverse universe = BindingUniverse.create();
		ProvidedPhysicalProperties parameterized = ProvidedPhysicalProperties.builder()
				.parameterBindings(universe.maskOf(List.of("outer")))
				.build();

		assertFalse(parameterized.satisfies(RequiredPhysicalProperties.ANY));
	}

	@Test
	void physicalOperatorMustMatchWhenRequired() {
		ProvidedPhysicalProperties provided = ProvidedPhysicalProperties.builder()
				.operator(PhysicalOperatorId.of("index-scan"))
				.build();

		assertTrue(provided.satisfies(RequiredPhysicalProperties.builder()
				.operator(PhysicalOperatorId.of("index-scan"))
				.build()));
		assertFalse(provided.satisfies(RequiredPhysicalProperties.builder()
				.operator(PhysicalOperatorId.of("table-scan"))
				.build()));
	}

	@Test
	void concreteAccessPathRoundTripsThroughTypedProperties() {
		PhysicalProperties physicalProperties = PhysicalProperties.builder()
				.accessPath("lmdb-index-spoc")
				.build();
		MemoExpr expression = MemoExpr.physical(1, 2, new SingletonSet(), List.of(), "lmdb-access-path",
				physicalProperties, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), null);
		PhysicalOperatorId operator = PhysicalOperatorId.from(expression);
		BindingUniverse universe = BindingUniverse.create();

		ProvidedPhysicalProperties provided = TypedPhysicalPropertyBridge.provided(physicalProperties, universe,
				operator);
		RequiredPhysicalProperties required = TypedPhysicalPropertyBridge.required(physicalProperties, universe);

		assertEquals(PhysicalOperatorId.of("access-path:lmdb-index-spoc"), operator);
		assertTrue(provided.satisfies(required));
	}

	@Test
	void physicalOperatorIdentityDoesNotIncludeChildTopology() {
		MemoExpr first = MemoExpr.physical(1, 2, new Join(new SingletonSet(), new SingletonSet()), List.of(10, 11),
				"hash-join", PhysicalProperties.ANY, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), null);
		MemoExpr second = MemoExpr.physical(3, 4, new Join(new SingletonSet(), new SingletonSet()), List.of(20, 21),
				"hash-join", PhysicalProperties.ANY, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), null);

		assertEquals(PhysicalOperatorId.from(first), PhysicalOperatorId.from(second),
				"Child group topology belongs to the scoped candidate recipe, not the physical operator identity");
	}
}
